import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { db } from '../utils/firebase';
import { doc, getDoc, collection, addDoc, query, orderBy, onSnapshot } from 'firebase/firestore';

export default function PollResults() {
  const { id } = useParams();
  const [poll, setPoll] = useState(null);
  const [messages, setMessages] = useState([]);
  const [message, setMessage] = useState('');
  const [copied, setCopied] = useState(false); // For handling the "Link Copied" state

  // Fetch poll results data from Firestore
  useEffect(() => {
    const fetchPollData = async () => {
      const ref = doc(db, 'polls', id);
      const snap = await getDoc(ref);
      if (snap.exists()) {
        setPoll(snap.data());
      } else {
        setPoll({ error: 'Poll not found' });
      }
    };
    fetchPollData();
  }, [id]);

  // Fetch and display messages from Firestore for chatbox
  useEffect(() => {
    const messagesRef = collection(db, 'polls', id, 'chat');
    const q = query(messagesRef, orderBy('timestamp', 'asc'));

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const messagesData = querySnapshot.docs.map((doc) => doc.data());
      setMessages(messagesData);
    });

    return () => unsubscribe();
  }, [id]);

  // Handle submitting a new message
  const handleSubmit = async () => {
    if (message.trim() !== '') {
      try {
        await addDoc(collection(db, 'polls', id, 'chat'), {
          message,
          timestamp: new Date(),
        });
        setMessage(''); // Clear input after sending
      } catch (err) {
        console.error('Error sending message:', err);
      }
    }
  };

  // Copy poll link to clipboard
  const handleCopy = () => {
    navigator.clipboard.writeText(window.location.href); // Copy the current URL
    setCopied(true);
    setTimeout(() => setCopied(false), 2000); // Reset after 2 seconds
  };

  if (!poll) return <div className="p-4">Loading...</div>;

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center p-4">
      <h1 className="text-3xl font-bold mb-4">{poll?.name}</h1>

      {/* Share Poll Button */}
      <button
        onClick={handleCopy}
        className="mt-4 bg-blue-600 text-white px-6 py-2 rounded hover:bg-blue-700"
      >
        {copied ? 'Link Copied!' : 'Share Poll'}
      </button>

      {/* Poll Results */}
      <div className="mt-8 w-full max-w-md bg-white p-6 rounded-lg shadow-md">
        <h2 className="text-xl font-semibold mb-4">Poll Results</h2>
        {poll.responses && poll.responses.length > 0 ? (
          <div>
            {poll.responses.map((response, index) => (
              <div key={index} className="mb-4">
                <h3 className="font-semibold">{response.name}</h3>
                <ul>
                  {response.availability.map((availability, i) => (
                    <li key={i}>
                      {availability.date} - {availability.times.join(', ')}
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        ) : (
          <p>No responses yet.</p>
        )}
      </div>

      {/* Chat Messages Display */}
      <div className="w-full max-w-md bg-white p-4 rounded-lg shadow-md mt-6">
        <h2 className="text-xl font-semibold mb-4">Chat</h2>
        <div className="max-h-64 overflow-y-auto mb-4">
          {messages.map((msg, index) => (
            <div key={index} className="mb-2">
              <p>{msg.message}</p>
            </div>
          ))}
        </div>

        {/* Chat Input */}
        <div className="flex gap-2">
          <input
            type="text"
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="Type a message..."
            className="w-full p-2 border rounded"
          />
          <button
            onClick={handleSubmit}
            className="bg-blue-600 text-white px-4 py-2 rounded"
          >
            Send
          </button>
        </div>
      </div>
    </div>
  );
}
